import json
import os
import pymysql

def lambda_handler(event, context):
    db_host = os.environ.get('DB_HOST')
    db_user = os.environ.get('DB_USER')
    db_password = os.environ.get('DB_PASSWORD')
    db_name = os.environ.get('DB_NAME')

    if not all([db_host, db_user, db_password, db_name]):
        return {
            'statusCode': 500,
            'body': json.dumps('Database connection environment variables are not set.')
        }

    try:
        conn = pymysql.connect(host=db_host, user=db_user, passwd=db_password, db=db_name, connect_timeout=5)
    except pymysql.Error as e:
        print(f"ERROR: Could not connect to MySQL instance: {e}")
        return {
            'statusCode': 500,
            'body': json.dumps(f'Error connecting to database: {e}')
        }

    try:
        cursor = conn.cursor(pymysql.cursors.DictCursor)

        # Parse query parameters from API Gateway event
        query_params = event.get('queryStringParameters', {})
        if query_params is None:
            query_params = {}

        base_sql = "SELECT product_id, name, description, price, category FROM products WHERE 1=1"
        sql_conditions = []
        sql_values = []

        if 'name' in query_params and query_params['name']:
            sql_conditions.append("name LIKE %s")
            sql_values.append(f"%{query_params['name']}%")

        if 'category' in query_params and query_params['category']:
            sql_conditions.append("category = %s")
            sql_values.append(query_params['category'])

        if 'min_price' in query_params and query_params['min_price']:
            try:
                min_price = float(query_params['min_price'])
                sql_conditions.append("price >= %s")
                sql_values.append(min_price)
            except ValueError:
                return {
                    'statusCode': 400,
                    'body': json.dumps('Invalid min_price parameter. Must be a number.')
                }

        if 'max_price' in query_params and query_params['max_price']:
            try:
                max_price = float(query_params['max_price'])
                sql_conditions.append("price <= %s")
                sql_values.append(max_price)
            except ValueError:
                return {
                    'statusCode': 400,
                    'body': json.dumps('Invalid max_price parameter. Must be a number.')
                }

        if sql_conditions:
            base_sql += " AND " + " AND ".join(sql_conditions)

        cursor.execute(base_sql, tuple(sql_values))
        products = cursor.fetchall()

        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json'
            },
            'body': json.dumps(products)
        }

    except pymysql.Error as e:
        print(f"ERROR: MySQL error: {e}")
        return {
            'statusCode': 500,
            'body': json.dumps(f'Error executing query: {e}')
        }
    except Exception as e:
        print(f"ERROR: An unexpected error occurred: {e}")
        return {
            'statusCode': 500,
            'body': json.dumps(f'An unexpected error occurred: {e}')
        }
    finally:
        if 'conn' in locals() and conn.open:
            conn.close()